def fibonacci_iterative(n):
    if n <= 1:
        return n

    a, b = 0, 1
    for _ in range(2, n + 1):
        a, b = b, a + b
    return b


def fibonacci_recursive(n):
    if n <= 1:
        return n
    return fibonacci_recursive(n - 1) + fibonacci_recursive(n - 2)


# Memoization ile hizlandirma
memo = {}

def fibonacci_memo(n):
    if n in memo:
        return memo[n]
    if n <= 1:
        return n
    result = fibonacci_memo(n - 1) + fibonacci_memo(n - 2)
    memo[n] = result
    return result


print("Iteratif Fibonacci (0-10):")
print([fibonacci_iterative(i) for i in range(11)])

print("\nRecursive Fibonacci (0-10):")
print([fibonacci_recursive(i) for i in range(11)])

print("\nMemoization ile 30. Fibonacci:", fibonacci_memo(30))
print("Iteratif ile 30. Fibonacci:", fibonacci_iterative(30))
